  ('social-worker-moex-08142', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區照顧「最重要」的目標是：', '["生活正常化", "去機構化", "減少照顧的成本", "提供多元化選擇"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08143', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '計劃一個適合解決問題的處遇方法非常重要，以一位因為身體健康問題而導致社會疏離和沮喪的案主為例， 下面那種處遇方法被證明比較有效？', '["領悟取向治療法", "行為技術訓練", "參與教育性團體", "認知治療法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08144', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會計畫中，問題的確認與分析是工作的第一個階段，下列那一項不是核心工作項目：', '["瞭解有那些社會價值被威脅", "決定問題分析者的角色", "詳細描述問題的類型", "瞭解那些人受到問題的影響和範圍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08145', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作教育需要包括一些知識的領域，下列那一項不是絕對必要性的知識？', '["社會環境中的人類行為", "社會工作實施方法", "社會工作的歷史觀點與趨勢", "社會福利政策與服務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08146', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '由於遊民、身障者、失業者人口數目劇增，近來社會工作直接服務的角色不斷擴充當中，這個角色是：', '["個案管理者", "方案發展者", "個案權益倡導者", "個案諮詢者或被諮詢者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08147', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '選擇一個好的社會工作理論或模式於實施當中常有一些標準（criteria），下列那一項不是該有的標準？', '["理論被實證研究支持的程度", "倫理的考量", "社會工作員具備的知識和技術層次", "機構的政策"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08148', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '綜融性社會工作實務工作者的功能有三個，以下那一個不是其功能？', '["諮詢者", "研究者", "資源管理者", "教育者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
